"use server";

import { revalidatePath } from "next/cache";

import { clientService } from "@/services/client.service";
import { getCurrentUser } from "@/lib/auth/session";
import { createClientSchema } from "@/lib/validations/client";
import { ROUTES } from "@/lib/constants";

/* ============================================
   Create Client Server Action
   ============================================ */

export type CreateClientState = {
  success: boolean;
  error?: string;
  clientId?: string;
};

export async function createClientAction(
  _prev: CreateClientState,
  formData: FormData
): Promise<CreateClientState> {
  const user = await getCurrentUser();
  if (!user) {
    return { success: false, error: "ЩҠШ¬ШЁ ШӘШіШ¬ЩҠЩ„ Ш§Щ„ШҜШ®ЩҲЩ„" };
  }

  const parsed = createClientSchema.safeParse({
    name: formData.get("name"),
    company: formData.get("company"),
    email: formData.get("email"),
    phone: formData.get("phone"),
    notes: formData.get("notes"),
    status: formData.get("status"),
  });

  if (!parsed.success) {
    return {
      success: false,
      error: parsed.error.issues[0]?.message ?? "ШЁЩҠШ§ЩҶШ§ШӘ ШәЩҠШұ ШөШ§Щ„ШӯШ©",
    };
  }

  try {
    const client = await clientService.create(
      {
        userId: user.id,
        name: parsed.data.name,
        company: parsed.data.company,
        email: parsed.data.email,
        phone: parsed.data.phone,
        notes: parsed.data.notes,
        status: parsed.data.status,
      },
      { actorId: user.id }
    );

    revalidatePath(ROUTES.DASHBOARD_CLIENTS);
    return { success: true, clientId: client.id };
  } catch (err) {
    if (err instanceof Error && err.message.includes("Unique constraint")) {
      return { success: false, error: "Ш§Щ„ШЁШұЩҠШҜ Ш§Щ„ШҘЩ„ЩғШӘШұЩҲЩҶЩҠ Щ…ШіШӘШ®ШҜЩ… ШЁШ§Щ„ЩҒШ№Щ„" };
    }
    return { success: false, error: "ЩҒШҙЩ„ ЩҒЩҠ ШҘЩҶШҙШ§ШЎ Ш§Щ„Ш№Щ…ЩҠЩ„" };
  }
}

"use server";

import { clientService } from "@/services/client.service";
import { getCurrentUser } from "@/lib/auth/session";
import { PAGINATION } from "@/lib/constants";
import type { ClientFilterValue, ClientSortValue } from "@/lib/validations/client";

/* ============================================
   Get Clients Server Action
   Paginated list with search, filter, and sort.
   ============================================ */

export async function getClientsAction(params?: {
  page?: number;
  pageSize?: number;
  search?: string;
  filter?: ClientFilterValue;
  sort?: ClientSortValue;
}) {
  const user = await getCurrentUser();
  if (!user) {
    return {
      items: [],
      total: 0,
      page: 1,
      pageSize: PAGINATION.DEFAULT_PAGE_SIZE,
      totalPages: 0,
    };
  }

  const page = params?.page ?? PAGINATION.DEFAULT_PAGE;
  const pageSize = params?.pageSize ?? 10;
  const skip = (page - 1) * pageSize;

  const { items, total } = await clientService.list({
    userId: user.id,
    skip,
    take: pageSize,
    search: params?.search,
    filter: params?.filter ?? "all",
    sort: params?.sort ?? "newest",
  });

  const totalPages = Math.ceil(total / pageSize);

  return {
    items: items.map((c) => ({
      id: c.id,
      clientCode: c.clientCode,
      name: c.name,
      company: c.company,
      phone: c.phone,
      email: c.email,
      notes: c.notes,
      status: c.status,
      archivedAt: c.archivedAt,
      projectCount: c._count.projects,
      createdAt: c.createdAt,
      updatedAt: c.updatedAt,
    })),
    total,
    page,
    pageSize,
    totalPages,
  };
}

"use server";

import { revalidatePath } from "next/cache";

import { clientService } from "@/services/client.service";
