/* ============================================
   Delete (Archive) Client Server Action
   Soft delete only вҖ” never permanently deletes.
   ============================================ */

export async function deleteClientAction(id: string): Promise<{
  success: boolean;
  error?: string;
}> {
  const user = await getCurrentUser();
  if (!user) {
    return { success: false, error: "ЩҠШ¬ШЁ ШӘШіШ¬ЩҠЩ„ Ш§Щ„ШҜШ®ЩҲЩ„" };
  }

  try {
    await clientService.archive(id, { actorId: user.id });
    revalidatePath(ROUTES.DASHBOARD_CLIENTS);
    return { success: true };
  } catch {
    return { success: false, error: "ЩҒШҙЩ„ ЩҒЩҠ ШЈШұШҙЩҒШ© Ш§Щ„Ш№Щ…ЩҠЩ„" };
