    .string()
    .max(100, "Ш§ШіЩ… Ш§Щ„ШҙШұЩғШ© ЩҠШ¬ШЁ ШЈЩҶ ЩҠЩғЩҲЩҶ 100 ШӯШұЩҒ ЩғШӯШҜ ШЈЩӮШөЩү")
