    .string()
    .max(1000, "Ш§Щ„Щ…Щ„Ш§ШӯШёШ§ШӘ ЩҠШ¬ШЁ ШЈЩҶ ШӘЩғЩҲЩҶ 1000 ШӯШұЩҒ ЩғШӯШҜ ШЈЩӮШөЩү")
