const globalForPrisma = globalThis as unknown as {
  prisma: PrismaClient | undefined;
};

function createPrismaClient() {
  const adapter = new PrismaPg({
    connectionString: process.env.DATABASE_URL,
  });
  return new PrismaClient({ adapter });
}

export const prisma = globalForPrisma.prisma ?? createPrismaClient();

if (process.env.NODE_ENV !== "production") {
  globalForPrisma.prisma = prisma;
}

import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

/**
 * Merge Tailwind CSS classes with proper conflict resolution.
 * Combines `clsx` for conditional classes and `tailwind-merge`
 * for deduplication of conflicting Tailwind utilities.
 */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

/* ============================================
   Formatting Utilities
   ============================================ */

/**
 * Format bytes into a human-readable string.
 * @example formatBytes(1536) вҶ’ "1.5 KB"
 */
export function formatBytes(bytes: number, decimals = 2): string {
  if (bytes === 0) return "0 Bytes";
  if (bytes < 0) return "вҖ”";
  if (!Number.isFinite(bytes)) return "вҖ”";

  const k = 1024;
  const dm = decimals < 0 ? 0 : decimals;
  const sizes = ["Bytes", "KB", "MB", "GB", "TB", "PB"];
  const i = Math.floor(Math.log(bytes) / Math.log(k));

  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(dm))} ${sizes[i]}`;
}

/**
 * Format a date for display in the Arabic locale.
 * @example formatDate("2025-01-15") вҶ’ "ЩЎЩҘ ЩҠЩҶШ§ЩҠШұ ЩўЩ ЩўЩҘ"
 */
export function formatDate(
  date: Date | string | number,
  locale = "ar-SA",
  options: Intl.DateTimeFormatOptions = {
    year: "numeric",
    month: "long",
    day: "numeric",
  }
): string {
  const d = new Date(date);
  if (Number.isNaN(d.getTime())) return "вҖ”";
  return new Intl.DateTimeFormat(locale, options).format(d);
}

/**
 * Format a date and time for display.
 */
export function formatDateTime(
  date: Date | string | number,
  locale = "ar-SA"
): string {
  return formatDate(date, locale, {
    year: "numeric",
    month: "short",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
}

/**
 * Format a number with thousands separators.
 */
export function formatNumber(
  value: number,
  locale = "ar-SA"
): string {
  return new Intl.NumberFormat(locale).format(value);
}

