export const phoneSchema = z
  .string()
  .regex(
    /^(\+?966|0)?5\d{8}$/,
    "ШұЩӮЩ… Ш§Щ„ЩҮШ§ШӘЩҒ ШәЩҠШұ ШөШ§Щ„Шӯ вҖ” Щ…Ш«Ш§Щ„: 05xxxxxxxx"
  )
  .optional()
  .or(z.literal(""));

/* в”Җв”Җ Composite schemas в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */

export const loginSchema = z.object({
