import { describe, it, expect } from "vitest";

import {
  createClientSchema,
  updateClientSchema,
  clientQuerySchema,
  clientStatusSchema,
} from "@/lib/validations/client";

/* ============================================
   Client Validation Tests
   ============================================ */

describe("createClientSchema", () => {
  const validInput = {
    name: "ГҳВЈГҳВӯГҷвҖҰГҳВҜ ГҷвҖҰГҳВӯГҷвҖҰГҳВҜ",
    email: "ahmed@example.com",
    phone: "0501234567",
    company: "ГҳВҙГҳВұГҷЖ’ГҳВ© ГҳВ§ГҷвҖһГҳВҘГҳВЁГҳВҜГҳВ§ГҳВ№",
    notes: "ГҳВ№ГҷвҖҰГҷЕ ГҷвҖһ ГҷвҖҰГҷвҖҰГҷЕ ГҳВІ",
    status: "ACTIVE" as const,
  };

  /* ГўвҖқвӮ¬ГўвҖқвӮ¬ Valid input ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ */
  it("accepts valid input with all fields", () => {
    const result = createClientSchema.safeParse(validInput);
    expect(result.success).toBe(true);
  });

  it("accepts valid input without optional fields", () => {
    const result = createClientSchema.safeParse({
      name: "ГҳВЈГҳВӯГҷвҖҰГҳВҜ",
      email: "ahmed@example.com",
      status: "ACTIVE",
    });
    expect(result.success).toBe(true);
  });

  /* ГўвҖқвӮ¬ГўвҖқвӮ¬ Name validation ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ */
  it("rejects when name is missing", () => {
    const result = createClientSchema.safeParse({
      email: "ahmed@example.com",
      status: "ACTIVE",
    });
    expect(result.success).toBe(false);
  });

  it("rejects when name is too short", () => {
    const result = createClientSchema.safeParse({
      ...validInput,
      name: "ГҳВЈ",
    });
    expect(result.success).toBe(false);
    if (!result.success) {
      expect(result.error.issues[0]?.message).toContain("ГҳВӯГҳВұГҷВҒГҷЕ ГҷвҖ ");
    }
  });

  it("rejects when name exceeds 50 characters", () => {
    const result = createClientSchema.safeParse({
      ...validInput,
      name: "ГҳВЈ".repeat(51),
    });
