  formData: FormData
): Promise<CreateProjectState> {
  const parsed = createProjectSchema.safeParse({
    clientId: formData.get("clientId"),
    name: formData.get("name"),
    description: formData.get("description"),
    expiresAt: formData.get("expiresAt"),
  });

  if (!parsed.success) {
    return {
      success: false,
      error: parsed.error.issues[0]?.message ?? "ГҳВЁГҷЕ ГҳВ§ГҷвҖ ГҳВ§ГҳВӘ ГҳВәГҷЕ ГҳВұ ГҳВөГҳВ§ГҷвҖһГҳВӯГҳВ©",
    };
  }

  try {
    await projectService.create({
      clientId: parsed.data.clientId,
      name: parsed.data.name,
      description: parsed.data.description,
      expiresAt: parsed.data.expiresAt,
    });

    revalidatePath(ROUTES.DASHBOARD_PROJECTS);
    return { success: true };
  } catch {
    return { success: false, error: "ГҷВҒГҳВҙГҷвҖһ ГҷВҒГҷЕ  ГҳВҘГҷвҖ ГҳВҙГҳВ§ГҳВЎ ГҳВ§ГҷвҖһГҷвҖҰГҳВҙГҳВұГҷЛҶГҳВ№" };
  }
}
