  it("rejects invalid email format", () => {
    const result = createClientSchema.safeParse({
      ...validInput,
      email: "not-an-email",
    });
    expect(result.success).toBe(false);
  });

  it("rejects when email is empty", () => {
    const result = createClientSchema.safeParse({
      ...validInput,
      email: "",
    });
    expect(result.success).toBe(false);
    if (!result.success) {
      expect(result.error.issues[0]?.message).toContain("ГҷвҖҰГҳВ·ГҷвҖһГҷЛҶГҳВЁ");
    }
  });

  /* ГўвҖқвӮ¬ГўвҖқвӮ¬ Phone validation ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ */
  it("accepts empty phone", () => {
    const result = createClientSchema.safeParse({
      ...validInput,
      phone: "",
    });
    expect(result.success).toBe(true);
  });

  it("rejects invalid phone format", () => {
    const result = createClientSchema.safeParse({
      ...validInput,
      phone: "12345",
    });
    expect(result.success).toBe(false);
  });

  /* ГўвҖқвӮ¬ГўвҖқвӮ¬ Status validation ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ГўвҖқвӮ¬ */
