            <Label htmlFor="name">
              Ш§Щ„Ш§ШіЩ… <span className="text-destructive">*</span>
            </Label>
            <Input
              id="name"
              placeholder="Ш§ШіЩ… Ш§Щ„Ш№Щ…ЩҠЩ„"
              aria-invalid={!!errors.name}
