import { z } from "zod";

/* в”Җв”Җ Common field schemas (reusable) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */

export const emailSchema = z
  .string()
  .min(1, "Ш§Щ„ШЁШұЩҠШҜ Ш§Щ„ШҘЩ„ЩғШӘШұЩҲЩҶЩҠ Щ…Ш·Щ„ЩҲШЁ")
  .email("Ш§Щ„ШЁШұЩҠШҜ Ш§Щ„ШҘЩ„ЩғШӘШұЩҲЩҶЩҠ ШәЩҠШұ ШөШ§Щ„Шӯ");

export const passwordSchema = z
  .string()
  .min(8, "ЩғЩ„Щ…Ш© Ш§Щ„Щ…ШұЩҲШұ ЩҠШ¬ШЁ ШЈЩҶ ШӘЩғЩҲЩҶ 8 ШЈШӯШұЩҒ Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„")
  .regex(/[A-Z]/, "ЩҠШ¬ШЁ ШЈЩҶ ШӘШӯШӘЩҲЩҠ Ш№Щ„Щү ШӯШұЩҒ ЩғШЁЩҠШұ ЩҲШ§ШӯШҜ Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„")
  .regex(/[a-z]/, "ЩҠШ¬ШЁ ШЈЩҶ ШӘШӯШӘЩҲЩҠ Ш№Щ„Щү ШӯШұЩҒ ШөШәЩҠШұ ЩҲШ§ШӯШҜ Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„")
  .regex(/[0-9]/, "ЩҠШ¬ШЁ ШЈЩҶ ШӘШӯШӘЩҲЩҠ Ш№Щ„Щү ШұЩӮЩ… ЩҲШ§ШӯШҜ Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„");

export const nameSchema = z
  .string()
  .min(2, "Ш§Щ„Ш§ШіЩ… ЩҠШ¬ШЁ ШЈЩҶ ЩҠЩғЩҲЩҶ ШӯШұЩҒЩҠЩҶ Ш№Щ„Щү Ш§Щ„ШЈЩӮЩ„")
  .max(50, "Ш§Щ„Ш§ШіЩ… ЩҠШ¬ШЁ ШЈЩҶ ЩҠЩғЩҲЩҶ 50 ШӯШұЩҒШ§ЩӢ ЩғШӯШҜ ШЈЩӮШөЩү");

export const phoneSchema = z
  .string()
  .regex(
    /^(\+?966|0)?5\d{8}$/,
    "ШұЩӮЩ… Ш§Щ„ЩҮШ§ШӘЩҒ ШәЩҠШұ ШөШ§Щ„Шӯ вҖ” Щ…Ш«Ш§Щ„: 05xxxxxxxx"
  )
  .optional()
  .or(z.literal(""));

/* в”Җв”Җ Composite schemas в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */

export const loginSchema = z.object({
  email: emailSchema,
  password: z.string().min(1, "ЩғЩ„Щ…Ш© Ш§Щ„Щ…ШұЩҲШұ Щ…Ш·Щ„ЩҲШЁШ©"),
});

export const registerSchema = z
  .object({
    name: nameSchema,
    email: emailSchema,
    password: passwordSchema,
    confirmPassword: z.string(),
  })
  .refine((data) => data.password === data.confirmPassword, {
    message: "ЩғЩ„Щ…ШӘШ§ Ш§Щ„Щ…ШұЩҲШұ ШәЩҠШұ Щ…ШӘШ·Ш§ШЁЩӮШӘЩҠЩҶ",
    path: ["confirmPassword"],
  });

export type LoginInput = z.infer<typeof loginSchema>;
export type RegisterInput = z.infer<typeof registerSchema>;

