import { cookies } from "next/headers";
import { SignJWT, jwtVerify } from "jose";

import {
  SESSION_COOKIE_NAME,
  SESSION_ALG,
  SESSION_MAX_AGE,
  cookieOptions,
} from "@/lib/auth/config";
import {
  UnauthorizedError,
  ExpiredSessionError,
  ForbiddenError,
} from "@/lib/auth/errors";
import type { SessionUser, UserRole } from "@/types/auth";

/* ============================================
   Session Utilities
   JWT-based session management using jose.
   Works in both Node.js and Edge runtimes.
   ============================================ */

function getSecret(): Uint8Array {
  const secret = process.env.AUTH_SECRET;
  if (!secret) {
    throw new Error("AUTH_SECRET environment variable is required");
  }
  return new TextEncoder().encode(secret);
}

/** JWT payload shape (internal). */
type SessionPayload = {
  sub: string;
  email: string;
  name: string;
  role: UserRole;
  avatar?: string | null;
  iat: number;
  exp: number;
};

/**
 * Create a signed session JWT and set it as an httpOnly cookie.
 * Call this after successful authentication.
 */
export async function createSession(user: {
  id: string;
  email: string;
  name: string;
  role: UserRole;
  avatar?: string | null;
}): Promise<void> {
  const token = await new SignJWT({
    sub: user.id,
    email: user.email,
    name: user.name,
    role: user.role,
    avatar: user.avatar ?? null,
  })
    .setProtectedHeader({ alg: SESSION_ALG })
    .setIssuedAt()
    .setExpirationTime(`${SESSION_MAX_AGE}s`)
    .sign(getSecret());

  const store = await cookies();
  store.set(SESSION_COOKIE_NAME, token, cookieOptions);
}

/**
 * Verify and decode the session JWT from the cookie.
 * Returns `null` if no session exists or the token is invalid.
 */
export async function getSession(): Promise<SessionUser> {
  const store = await cookies();
  const token = store.get(SESSION_COOKIE_NAME)?.value;

  if (!token) return null;

  try {
    const { payload } = await jwtVerify(token, getSecret(), {
      algorithms: [SESSION_ALG],
    });

    return {
      id: payload.sub as string,
      email: payload.email as string,
      name: payload.name as string,
      role: payload.role as UserRole,
      avatar: (payload.avatar as string | null) ?? null,
    };
  } catch {
    // Token is expired, malformed, or signature mismatch
    return null;
  }
}

/**
 * Get the currently authenticated user.
 * Returns `null` if not authenticated вҖ” does not throw.
 */
export async function getCurrentUser(): Promise<SessionUser> {
  return getSession();
}

/**
 * Require an authenticated user. Throws `UnauthorizedError` if
 * no valid session exists, or `ExpiredSessionError` if the
 * session token is present but expired.
 */
export async function requireUser(): Promise<NonNullable<SessionUser>> {
  const store = await cookies();
  const token = store.get(SESSION_COOKIE_NAME)?.value;

  if (!token) {
    throw new UnauthorizedError();
  }

  try {
    const { payload } = await jwtVerify(token, getSecret(), {
      algorithms: [SESSION_ALG],
    });

    return {
      id: payload.sub as string,
      email: payload.email as string,
      name: payload.name as string,
      role: payload.role as UserRole,
      avatar: (payload.avatar as string | null) ?? null,
    };
  } catch (err) {
    // Distinguish expired token from other errors
    if (err instanceof Error && err.name === "JWTExpired") {
      throw new ExpiredSessionError();
    }
    throw new UnauthorizedError();
  }
}

/**
 * Require the authenticated user to have one of the specified roles.
 * Throws `UnauthorizedError` if not logged in, `ForbiddenError` if
 * the user's role is not in the allowed list.
 */
export async function requireRole(
  ...allowedRoles: UserRole[]
): Promise<NonNullable<SessionUser>> {
  const user = await requireUser();

  if (!allowedRoles.includes(user.role)) {
    throw new ForbiddenError();
  }

  return user;
}

/**
 * Destroy the session by deleting the session cookie.
 */
export async function destroySession(): Promise<void> {
  const store = await cookies();
  store.delete(SESSION_COOKIE_NAME);
}

import type { UserRole as PrismaUserRole } from "@prisma/client";

/* ============================================
   Auth Types
   Aligned with the Prisma UserRole enum.
   ============================================ */

export type UserRole = PrismaUserRole;

export type AuthenticatedUser = {
  id: string;
  email: string;
  name: string;
  role: UserRole;
  avatar?: string | null;
};

export type SessionUser = AuthenticatedUser | null;

export type SessionStatus = "loading" | "authenticated" | "unauthenticated";

/* ============================================
   Auth Configuration
   Session, cookie, and rate-limit constants.
   ============================================ */

/* в”Җв”Җ Session в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */

export const SESSION_COOKIE_NAME = "pph-session";

/** JWT signing algorithm. */
export const SESSION_ALG = "HS256";

/** Session lifetime in seconds (7 days). */
export const SESSION_MAX_AGE = 60 * 60 * 24 * 7;

/** Grace period in seconds before a session is considered expired. */
export const SESSION_EXPIRY_THRESHOLD = 60 * 5; // 5 minutes

/* в”Җв”Җ Cookie в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */

export const cookieOptions = {
  httpOnly: true,
  sameSite: "lax" as const,
  secure: process.env.NODE_ENV === "production",
  path: "/",
  maxAge: SESSION_MAX_AGE,
};

/* в”Җв”Җ Rate Limiting в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */

export const RATE_LIMIT = {
  MAX_ATTEMPTS: 5,
  WINDOW_MS: 60 * 1000, // 1 minute
  LOCKOUT_MS: 15 * 60 * 1000, // 15 minutes
} as const;

/* в”Җв”Җ Timing Attack Prevention в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ */

/**
 * Pre-computed dummy bcrypt hash used when a user is not found.
 * Ensures bcrypt.compare always runs, preventing timing attacks
 * that could reveal whether an email is registered.
 */
export const DUMMY_HASH =
  "$2a$12$N9qo8uLOickgx2ZMRZoMy.MrMKxXQ9B7vrYqI2ZdD6J9.7KqYqYq2";

import bcrypt from "bcryptjs";

import { userRepository } from "@/repositories/user.repository";
import { activityService } from "@/services/activity.service";
import { createSession, destroySession } from "@/lib/auth/session";
import { checkRateLimit, recordFailedAttempt, clearRateLimit } from "@/lib/auth/rate-limit";
import { DUMMY_HASH } from "@/lib/auth/config";
import {
  InvalidCredentialsError,
  RateLimitExceededError,
} from "@/lib/auth/errors";
import type { AuthenticatedUser } from "@/types/auth";

/* ============================================
   Auth Service
   Business logic for authentication flows.
   Uses userRepository for DB access and
   activityService for audit logging.
   ============================================ */

export const authService = {
  /**
   * Authenticate a user with email and password.
   *
   * Security measures:
   * - Rate limited per IP
   * - Timing attack prevention (always runs bcrypt.compare)
   * - Does not reveal whether email exists
   * - Logs all attempts to audit log
   *
   * @returns The authenticated user (without password).
   * @throws InvalidCredentialsError | RateLimitExceededError
   */
  async login(
    email: string,
    password: string,
    options?: { ip?: string; userAgent?: string }
  ): Promise<AuthenticatedUser> {
    const rateLimitKey = options?.ip ?? email;

    checkRateLimit(rateLimitKey);

    const user = await userRepository.findByEmail(email);

    // Always run bcrypt.compare вҖ” even if user not found вҖ”
    // to prevent timing attacks that reveal email existence.
    const hashToCompare = user?.password ?? DUMMY_HASH;
    const isValid = await bcrypt.compare(password, hashToCompare);

    if (!user || !isValid) {
      recordFailedAttempt(rateLimitKey);

      // Log failed login attempt (without revealing whether email exists)
      if (user) {
        await activityService.log({
          userId: user.id,
          type: "LOGIN",
          entity: "auth",
          entityId: user.id,
          metadata: {
            success: false,
            ip: options?.ip,
            userAgent: options?.userAgent,
          },
        });
      }

      throw new InvalidCredentialsError();
    }

    // Success вҖ” clear rate limit and create session
    clearRateLimit(rateLimitKey);

    await createSession({
      id: user.id,
      email: user.email,
      name: user.name,
      role: user.role,
      avatar: user.avatar,
    });

    // Log successful login
    await activityService.log({
      userId: user.id,
      type: "LOGIN",
      entity: "auth",
      entityId: user.id,
      metadata: {
        success: true,
        ip: options?.ip,
        userAgent: options?.userAgent,
      },
    });

    return {
      id: user.id,
      email: user.email,
      name: user.name,
      role: user.role,
      avatar: user.avatar,
    };
  },

  /**
   * Log out the current user by destroying the session
   * and logging the event.
   */
  async logout(userId?: string): Promise<void> {
    await destroySession();

    if (userId) {
      await activityService.log({
        userId,
        type: "LOGOUT",
        entity: "auth",
        entityId: userId,
        metadata: {},
      });
    }
  },
};

